151→function isMissingDbObjectError(error: unknown): boolean {
152→  const pg = error as { code?: unknown; message?: unknown } | null;
153→  const code = typeof pg?.code === "string" ? pg.code : "";
154→  if (code === "42P01" || code === "42703") return true;
155→  const message = typeof pg?.message === "string" ? pg.message.toLowerCase() : "";
156→  return message.includes("does not exist") || message.includes("undefined column") || message.includes("undefined table");
157→}
