177→function sanitizeDetailsForContentHash(details: SubmissionDetails): Record<string, unknown> {
178→  const out: Record<string, unknown> = {};
179→  for (const [key, value] of Object.entries(details ?? {})) {
180→    if (HASH_DETAIL_OMIT_KEYS.has(key)) continue;
181→    out[key] = value;
182→  }
183→  return out;
184→}
