219→export function hammingDistance(a: string, b: string): number {
220→  if (a.length !== b.length) return Math.max(a.length, b.length);
221→  let distance = 0;
222→  for (let i = 0; i < a.length; i++) {
223→    const aBits = parseInt(a[i]!, 16).toString(2).padStart(4, "0");
224→    const bBits = parseInt(b[i]!, 16).toString(2).padStart(4, "0");
225→    for (let j = 0; j < 4; j++) {
226→      if (aBits[j] !== bBits[j]) distance++;
227→    }
228→  }
229→  return distance;
230→}
