242→    eventType: input.eventType,
243→    latitude: Number(input.location.latitude.toFixed(6)),
244→    longitude: Number(input.location.longitude.toFixed(6)),
245→    details: sanitizeDetailsForContentHash(input.details),
246→  };
247→  return hashText(JSON.stringify(stableSort(stablePayload)));
