254→export function computeExifTrustScore(input: {
255→  gps: SubmissionLocation | null;
256→  capturedAt: string | null;
257→  deviceMake: string | null;
258→  deviceModel: string | null;
259→  isLowEnd: boolean;
260→}): number {
261→  let score = 100;
262→  if (!input.gps) score -= 30;
263→  if (!input.capturedAt) score -= 20;
264→  if (!input.deviceMake) score -= 15;
265→  if (!input.deviceModel) score -= 15;
266→  if (input.isLowEnd && score < 50) {
267→    score = Math.min(score + 20, 50);
268→  }
269→  return Math.max(0, score);
270→}
