272→function buildRiskScore(components: RiskComponents): number {
273→  const weighted =
274→    0.25 * components.locationRisk +
275→    0.25 * components.photoRisk +
276→    0.15 * components.temporalRisk +
277→    0.20 * components.userRisk +
278→    0.15 * components.behavioralRisk;
279→  return Math.round(weighted);
280→}
