468→function blockDetailsForCode(code: string): { reason: string; status: number } {
469→  if (code === "duplicate_photo") {
470→    return { reason: "This photo has already been used for another submission", status: 409 };
471→  }
472→  if (code === "velocity_limit") {
473→    return { reason: "Submission rate too high. Please wait and retry.", status: 429 };
474→  }
475→  if (code === "impossible_travel") {
476→    return { reason: "Submission blocked due to impossible travel pattern", status: 409 };
477→  }
478→  if (code === "tor_exit_ip") {
479→    return { reason: "Submission blocked from Tor exit node", status: 403 };
480→  }
481→  if (code.startsWith("invalid_fuel_price")) {
482→    return { reason: "Invalid fuel price value", status: 400 };
483→  }
484→  return { reason: "Submission blocked by fraud controls", status: 400 };
485→}
