814→async function insertImageHashRecord(input: PersistSubmissionRiskInput): Promise<void> {
815→  try {
816→    let perceptualHash = input.perceptualHash ?? null;
817→    if (!perceptualHash && input.imageBuffer) {
818→      try {
819→        perceptualHash = await computePerceptualHash(input.imageBuffer);
820→      } catch {
821→        // Best-effort perceptual hash computation
822→      }
823→    }
824→    await query(
825→      `INSERT INTO submission_image_hashes (event_id, point_id, user_id, sha256_hash, perceptual_hash)
826→       VALUES ($1::uuid, $2, $3, $4, $5)
827→       ON CONFLICT (event_id) DO NOTHING`,
828→      [input.eventId, input.pointId, input.userId, input.imageHash, perceptualHash],
829→    );
830→  } catch (error) {
831→    if (isMissingDbObjectError(error) || isUniqueViolationError(error)) return;
832→    throw error;
833→  }
834→}
