836→async function upsertDeviceUsage(userId: string, clientDevice: ClientDeviceInfo | null): Promise<void> {
837→  if (!clientDevice?.deviceId) return;
838→  try {
839→    await query(
840→      `INSERT INTO device_user_map (device_id, user_id, first_seen, last_seen, submission_count)
841→       VALUES ($1, $2, NOW(), NOW(), 1)
842→       ON CONFLICT (device_id, user_id) DO UPDATE SET
843→         last_seen = NOW(),
844→         submission_count = device_user_map.submission_count + 1`,
845→      [clientDevice.deviceId, userId],
846→    );
847→  } catch (error) {
848→    if (isMissingDbObjectError(error)) return;
849→    throw error;
850→  }
851→}
