890→export async function persistSubmissionRiskArtifacts(input: PersistSubmissionRiskInput): Promise<void> {
891→  await Promise.all([
892→    persistContentHash(input.eventId, input.contentHash),
893→    insertImageHashRecord(input),
894→    upsertDeviceUsage(input.userId, input.clientDevice),
895→  ]);
896→
897→  if (input.reviewStatus === "pending_review") {
898→    await insertFraudAudit({
899→      eventId: input.eventId,
900→      userId: input.userId,
901→      action: "flagged",
902→      riskScore: input.riskScore,
903→      riskComponents: input.riskComponents,
904→      rule: input.reviewFlags[0] ?? "risk_score",
905→      notes: input.reviewFlags.length ? `flags=${input.reviewFlags.join(",")}` : null,
906→    });
907→  }
908→}
